Properties.commandText:
SET NOCOUNT ON;
DELETE FROM [EmployeeAddresses]
OUTPUT 1
WHERE [Id] = @p0;
DELETE FROM [EmployeeBanks]
OUTPUT 1
WHERE [Id] = @p1;
DELETE FROM [EmployeeDocuments]
OUTPUT 1
WHERE [Id] = @p2;
DELETE FROM [EmployeeEducations]
OUTPUT 1
WHERE [Id] = @p3;
DELETE FROM [EmployeeEmergencyContacts]
OUTPUT 1
WHERE [Id] = @p4;
DELETE FROM [EmployeeExperiences]
OUTPUT 1
WHERE [Id] = @p5;
DELETE FROM [EmployeeSkills]
OUTPUT 1
WHERE [Id] = @p6;
DELETE FROM [EmployeeTrainings]
OUTPUT 1
WHERE [Id] = @p7;
UPDATE [Employees] SET [EmploymentStatus] = @p8, [UpdatedDate] = @p9
WHERE [Id] = @p10;
SELECT @@ROWCOUNT;

SET NOCOUNT ON;
INSERT INTO [EmployeeAddresses] ([Id], [AddressType], [City], [Country], [CreatedBy], [CreatedDate], [EmployeeId], [IsActive], [IsPrimary], [Line1], [Line2], [PostalCode], [State], [UpdatedBy], [UpdatedDate])
VALUES (@p0, @p1, @p2, @p3, @p4, @p5, @p6, @p7, @p8, @p9, @p10, @p11, @p12, @p13, @p14);
INSERT INTO [EmployeeBanks] ([Id], [AccountHolderName], [AccountNumber], [BankName], [BranchName], [CreatedBy], [CreatedDate], [Currency], [EmployeeId], [IbanNumber], [IsActive], [RoutingNumber], [SwiftCode], [UpdatedBy], [UpdatedDate])
VALUES (@p15, @p16, @p17, @p18, @p19, @p20, @p21, @p22, @p23, @p24, @p25, @p26, @p27, @p28, @p29);
INSERT INTO [EmployeeDocuments] ([Id], [CreatedBy], [CreatedDate], [DocumentNumber], [DocumentType], [EmployeeId], [ExpiryDate], [FileUrl], [IsActive], [IssueDate], [Remark], [UpdatedBy], [UpdatedDate])
VALUES (@p30, @p31, @p32, @p33, @p34, @p35, @p36, @p37, @p38, @p39, @p40, @p41, @p42);
INSERT INTO [EmployeeEducations] ([Id], [CreatedBy], [CreatedDate], [DocumentUrl], [EmployeeId], [EndYear], [Grade], [Institution], [IsActive], [Qualification], [Specialization], [StartYear], [University], [UpdatedBy], [UpdatedDate])
VALUES (@p43, @p44, @p45, @p46, @p47, @p48, @p49, @p50, @p51, @p52, @p53, @p54, @p55, @p56, @p57);
INSERT INTO [EmployeeEmergencyContacts] ([Id], [Address], [AlternatePhone], [CreatedBy], [CreatedDate], [Email], [EmployeeId], [IsActive], [IsPrimary], [Name], [PrimaryPhone], [Relationship], [UpdatedBy], [UpdatedDate])
VALUES (@p58, @p59, @p60, @p61, @p62, @p63, @p64, @p65, @p66, @p67, @p68, @p69, @p70, @p71);
