SET NOCOUNT ON;
DELETE FROM [EmployeeAddresses]
OUTPUT 1
WHERE [Id] = @p0;
DELETE FROM [EmployeeBanks]
OUTPUT 1
WHERE [Id] = @p1;
DELETE FROM [EmployeeDocuments]
OUTPUT 1
WHERE [Id] = @p2;
DELETE FROM [EmployeeEducations]
OUTPUT 1
WHERE [Id] = @p3;
DELETE FROM [EmployeeEmergencyContacts]
OUTPUT 1
WHERE [Id] = @p4;
DELETE FROM [EmployeeExperiences]
OUTPUT 1
WHERE [Id] = @p5;
DELETE FROM [EmployeeSkills]
OUTPUT 1
WHERE [Id] = @p6;
DELETE FROM [EmployeeTrainings]
OUTPUT 1
WHERE [Id] = @p7;
UPDATE [Employees] SET [DesignationId] = @p8, [UpdatedDate] = @p9
WHERE [Id] = @p10;
SELECT @@ROWCOUNT;

SET NOCOUNT ON;
